nta.declaration:
const int N=4, Z=4, DIRS=4;
const int Tmin=2, Tmax=6, Tcross=2;
const int route[DIRS][2] = { {0,2}, {1,3}, {0,1}, {2,3} };

int[0,N] occ[Z];
bool waiting[N];
bool emerg[N];
int[0,N] dirOf[N];
int[0,N] order[N];
int[0,N] waitCount = 0;
bool emergencyMode = false;

broadcast chan request;   // V2I
broadcast chan done;      // V2I
broadcast chan warn;      // V2V

bool conflict(int a, int b) {
    return route[a][0]==route[b][0] || route[a][0]==route[b][1]
        || route[a][1]==route[b][0] || route[a][1]==route[b][1];
}
bool zonesFree(int d) { return occ[route[d][0]]==0 && occ[route[d][1]]==0; }
void reserve(int d) { occ[route[d][0]]++; occ[route[d][1]]++; }
void release(int d) { occ[route[d][0]]--; occ[route[d][1]]--; }

void startWait(int id, bool em, int d) {
    waiting[id]=true; emerg[id]=em; dirOf[id]=d;
    waitCount++; order[id]=waitCount;
}
void endWait(int id) {
    if (waiting[id]) {
        for (j : int[0,N-1]) if (order[j] > order[id]) order[j]--;
        order[id] = 0;
        waiting[id] = false;
        if (waitCount > 0) waitCount--;
    }
}
bool mayGo(int me) {
    for (j : int[0,N-1])
        if (j != me && waiting[j]) {
            if (emerg[j] && !emerg[me]) return false;
            if (emerg[j] == emerg[me] && order[j] < order[me] && conflict(dirOf[j], dirOf[me]))
                return false;
        }
    return true;
}

nta.system:
N0 = Vehicle(0, 0, false);
S1 = Vehicle(1, 1, false);
E2 = Vehicle(2, 2, true);
W3 = Vehicle(3, 3, false);
system N0, S1, E2, W3;
